def execute_move(self, from_pos, to_pos):
    from_row, from_col = int(from_pos[1]) - 1, ord(from_pos[0]) - ord('a')
    to_row, to_col = int(to_pos[1]) - 1, ord(to_pos[0]) - ord('a')

    piece = self.board.board[from_row][from_col]
    if not piece:
        print("No piece at the source position.")
        return

    # Check for valid move
    if abs(from_row - to_row) == 1 and abs(from_col - to_col) == 1:
        if (piece == 'W' and to_row < from_row) or (piece == 'B' and to_row > from_row):
            self.board.board[to_row][to_col] = piece
            self.board.board[from_row][from_col] = ''
            return

    # Check for capture
    if abs(from_row - to_row) == 2 and abs(from_col - to_col) == 2:
        intermediate_pos = chr((from_col + to_col) // 2 + ord('a')) + str((from_row + to_row) // 2 + 1)
        intermediate_row, intermediate_col = int(intermediate_pos[1]) - 1, ord(intermediate_pos[0]) - ord('a')

        if self.board.board[intermediate_row][intermediate_col] != ' ':
            self.board.board[to_row][to_col] = piece
            self.board.board[from_row][from_col] = ''
            self.board.board[intermediate_row][intermediate_col] = ''
            return

    print("Invalid move. Please try again.")
